class Item extends Model{use HasMediaAssets;protected $guarded=[];protected $casts=['is_stackable'=>'boolean','is_sellable'=>'boolean','allows_refinement'=>'boolean','max_stack'=>'integer','sell_price'=>'integer','required_level'=>'integer','max_health_bonus'=>'integer','attack_bonus'=>'integer','defense_bonus'=>'integer','accuracy_bonus'=>'integer','evasion_bonus'=>'integer','critical_chance_bonus'=>'decimal:2','attack_speed_bonus'=>'decimal:2','absorb_damage_basis_points'=>'integer'];protected static function booted(){static::creating(function($item){if(!array_key_exists('allows_refinement',$item->getAttributes())){$weapon=$item->equipment_type===EquipmentType::WEAPON&&($item->equipment_family===null||EquipmentItemFamily::isWeapon($item->equipment_family));$defensive=in_array($item->equipment_type,[EquipmentType::HELMET,EquipmentType::ARMOR,EquipmentType::GLOVES,EquipmentType::BOOTS],true)||$item->equipment_family===EquipmentItemFamily::SHIELD;$item->allows_refinement=$weapon||$defensive;$item->refinement_stat=$weapon?'attack':($defensive?'defense':'none');}});static::created(function($item){$common=ItemRarity::where('code','common')->first();if($common&&!$item->allowedRarities()->exists())$item->allowedRarities()->attach($common->id);});}public function monsterLootEntries(){return$this->hasMany(MonsterLootEntry::class);}public function requiredByConnections(){return$this->hasMany(ZoneConnection::class,'required_item_id');}public function characterItems(){return$this->hasMany(CharacterItem::class);}public function instances(){return$this->hasMany(ItemInstance::class);}public function allowedRarities(){return$this->belongsToMany(ItemRarity::class,'item_allowed_rarities');}public function allowedCharacterClasses(){return$this->belongsToMany(CharacterClass::class,'character_class_item')->withTimestamps();}public function visualAssets(){return$this->hasMany(ItemVisualAsset::class);}public function shopOffers(){return$this->hasMany(ShopOffer::class);}public function shopPurchases(){return$this->hasMany(ShopPurchase::class);}}
